
// --- NBT helpers (same typed system as litematic.html) ---------------------
const TAG = {End:0,Byte:1,Short:2,Int:3,Long:4,Float:5,Double:6,ByteArray:7,String:8,List:9,Compound:10,IntArray:11,LongArray:12};

function readNBT(buf) {
  const view = new DataView(buf); let pos = 0;
  function str() { const len=view.getUint16(pos);pos+=2; const v=new TextDecoder().decode(new Uint8Array(buf,pos,len));pos+=len;return v; }
  function readLong() { const hi=view.getInt32(pos),lo=view.getUint32(pos+4);pos+=8;return{_long:true,hi,lo}; }
  function rt(type) {
    switch(type){
      case 0:return null;
      case 1:return{_byte:true,v:view.getInt8(pos++)};
      case 2:{const v=view.getInt16(pos);pos+=2;return{_short:true,v};}
      case 3:{const v=view.getInt32(pos);pos+=4;return v;}
      case 4:return readLong();
      case 5:{const v=view.getFloat32(pos);pos+=4;return{_float:true,v};}
      case 6:{const v=view.getFloat64(pos);pos+=8;return v;}
      case 7:{const len=view.getInt32(pos);pos+=4;const arr=new Int8Array(len);for(let i=0;i<len;i++)arr[i]=view.getInt8(pos+i);pos+=len;return{_byteArray:true,data:arr};}
      case 8:return str();
      case 9:{const et=view.getUint8(pos++);const len=view.getInt32(pos);pos+=4;const arr=[];for(let i=0;i<len;i++)arr.push(rt(et));return{_list:true,etype:et,data:arr};}
      case 10:{const obj={_compound:true};while(true){const t=view.getUint8(pos++);if(t===0)break;const name=str();obj[name]=rt(t);}return obj;}
      case 11:{const len=view.getInt32(pos);pos+=4;const arr=new Int32Array(len);for(let i=0;i<len;i++){arr[i]=view.getInt32(pos);pos+=4;}return{_intArray:true,data:arr};}
      case 12:{const len=view.getInt32(pos);pos+=4;const arr=[];for(let i=0;i<len;i++)arr.push(readLong());return{_longArray:true,data:arr};}
    }
  }
  const rootType=view.getUint8(pos++);str();return rt(rootType);
}

function nbtGet(o,k){if(!o)return undefined;return o[k];}
function nbtList(o){if(!o)return[];if(o._list)return o.data;if(Array.isArray(o))return o;return[];}
function nbtInt(v){return typeof v==='number'?v:0;}
function nbtStr(v){return typeof v==='string'?v:'';}
function nbtLongToBI(l){const hi=BigInt(l.hi)&0xFFFFFFFFn,lo=BigInt(l.lo)&0xFFFFFFFFn;let v=(hi<<32n)|lo;if(v>=0x8000000000000000n)v-=0x10000000000000000n;return v;}

