function colorForBlock(name) {
  const n = name.replace('minecraft:','');
  if (n === 'air' || n === 'void_air' || n === 'cave_air') return null;
  const c = BLOCK_COLORS[n];
  if (c !== undefined) return c;
  // Hash-based fallback
  let h = 0;
  for (let i=0;i<n.length;i++) h=(h*31+n.charCodeAt(i))>>>0;
  const r=((h>>16)&0xFF); const g=((h>>8)&0xFF); const b=(h&0xFF);
  const lum = 0.2126*r+0.7152*g+0.0722*b;
  if(lum<30) { return ((r+60)<<16)|((g+60)<<8)|(b+60); }
  return (r<<16)|(g<<8)|b;
}

